#include <stdio.h>
#include <string.h>
int main() {
    int T, n;
    char team1[21], team2[21], s[21];
    int score1 = 0, score2 = 0;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        score1 = score2 = 0;
        strcpy(team1, "");
        strcpy(team2, "");
        for (int i = 0; i < n; i++) {
            scanf("%s", s);
            if (strcmp(team1, "") == 0) {
                strcpy(team1, s);
            } else if (strcmp(team2, "") == 0 && strcmp(s, team1) != 0) {
                strcpy(team2, s);
            }
            if (strcmp(s, team1) == 0) {
                score1++;
            } else if (strcmp(s, team2) == 0) {
                score2++;
            }
        }
        if (score1 > score2) {
            printf("%s\n", team1);
        } else if (score2 > score1) {
            printf("%s\n", team2);
        } else {
            printf("Draw\n");
        }
    }
    return 0;
}

